    fun performGesture(x1: Float, y1: Float, x2: Float, y2: Float, duration: Long) {
        Handler(Looper.getMainLooper()).post {
            val svc = MyAccessibilityService.instance
            if (svc != null) {
                val path = android.graphics.Path()
                path.moveTo(x1, y1)
                if (x1 == x2 && y1 == y2) {
